import { createClient } from "@/lib/supabase/server";
import { NextResponse } from "next/server";

// GET: export all user data as JSON
export async function GET() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const [transactions, budgets, categories, bills, debts, wallets] = await Promise.all([
    supabase.from("transactions").select("*").eq("user_id", user.id),
    supabase.from("budgets").select("*").eq("user_id", user.id),
    supabase.from("categories").select("*").eq("user_id", user.id),
    supabase.from("recurring_bills").select("*").eq("user_id", user.id),
    supabase.from("debts").select("*").eq("user_id", user.id),
    supabase.from("wallets").select("*").eq("user_id", user.id),
  ]);

  return NextResponse.json({
    exported_at: new Date().toISOString(),
    version: "1.0",
    transactions: transactions.data || [],
    budgets: budgets.data || [],
    categories: categories.data || [],
    recurring_bills: bills.data || [],
    debts: debts.data || [],
    wallets: wallets.data || [],
  });
}

// POST: import transactions from JSON backup
export async function POST(request: Request) {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const body = await request.json();
  const { transactions } = body;

  if (!Array.isArray(transactions) || transactions.length === 0) {
    return NextResponse.json({ error: "Tidak ada data transaksi untuk diimpor" }, { status: 400 });
  }

  // Strip IDs and set user_id so they're re-inserted as new records
  const cleaned = transactions.map(({ id: _id, user_id: _uid, created_at: _ca, ...rest }: any) => ({
    ...rest,
    user_id: user.id,
  }));

  const { error } = await supabase.from("transactions").insert(cleaned);
  if (error) return NextResponse.json({ error: error.message }, { status: 500 });

  return NextResponse.json({ imported: cleaned.length });
}

import { createClient } from "@/lib/supabase/server";
import { coreApi } from "@/lib/midtrans";
import { NextResponse } from "next/server";
import { nanoid } from "nanoid";

const PRICING = {
  plus: {
    monthly: 15000,
    yearly: 144000,
  },
  pro: {
    monthly: 29000,
    yearly: 278400,
  },
};

export async function POST(request: Request) {
  try {
    const supabase = await createClient();
    const { data: { user } } = await supabase.auth.getUser();

    if (!user) {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { planId, interval, payment_type, bank } = await request.json();

    if (!PRICING[planId as keyof typeof PRICING]) {
      return NextResponse.json({ error: "Invalid plan" }, { status: 400 });
    }

    const amount = PRICING[planId as keyof typeof PRICING][interval as 'monthly' | 'yearly'];
    const orderId = `SUBS-${planId.toUpperCase()}-${nanoid(8)}`;

    const parameter: any = {
      payment_type: payment_type,
      transaction_details: {
        order_id: orderId,
        gross_amount: amount,
      },
      customer_details: {
        email: user.email,
        first_name: user.user_metadata?.name || user.email?.split('@')[0],
      },
      item_details: [
        {
          id: planId,
          price: amount,
          quantity: 1,
          name: `Ngaturin ${planId.toUpperCase()} (${interval === 'monthly' ? 'Bulanan' : 'Tahunan'})`,
        },
      ],
    };

    if (payment_type === 'bank_transfer') {
      parameter.bank_transfer = { bank: bank };
    }

    const transaction = await coreApi.charge(parameter);

    // Clean up any existing pending transactions for this user to prevent clutter
    await supabase
      .from("subscriptions")
      .delete()
      .eq("user_id", user.id)
      .eq("status", "pending");

    // Save pending subscription to DB
    const { error: dbError } = await supabase
      .from("subscriptions")
      .insert({
        user_id: user.id,
        plan_id: planId,
        status: "pending",
        amount: amount,
        interval: interval,
        midtrans_order_id: orderId,
        payment_type: payment_type,
        payment_details: transaction // Save the full response here (VA numbers, actions array, etc)
      });

    if (dbError) {
      console.error("Database error:", dbError);
      return NextResponse.json({ error: "Failed to save transaction" }, { status: 500 });
    }

    return NextResponse.json({ 
      orderId: orderId 
    });

  } catch (error: unknown) {
    console.error("Checkout error:", error);
    const errorMessage = error instanceof Error ? error.message : "An unknown error occurred";
    return NextResponse.json({ error: errorMessage }, { status: 500 });
  }
}

import { createClient } from "@/lib/supabase/server";
import { NextResponse } from "next/server";

export async function PUT(
  request: Request,
  { params }: { params: Promise<{ id: string }> }
) {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { id } = await params;
  const body = await request.json();
  const { amount, category } = body;

  const updateData: Record<string, any> = {};
  if (amount !== undefined) updateData.amount = amount;
  if (category !== undefined) updateData.category = category;

  const { data, error } = await supabase
    .from("budgets")
    .update(updateData)
    .eq("id", id)
    .eq("user_id", user.id)
    .select()
    .single();

  if (error) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }

  return NextResponse.json(data);
}

export async function DELETE(
  request: Request,
  { params }: { params: Promise<{ id: string }> }
) {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  const { id } = await params;

  const { error } = await supabase
    .from("budgets")
    .delete()
    .eq("id", id)
    .eq("user_id", user.id);

  if (error) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }

  return NextResponse.json({ success: true });
}

import { NextResponse } from "next/server";

export async function POST(req: Request) {
  try {
    const { transactions, summary, investments, debts, bills } = await req.json();

    const totalExpense = summary?.totalExpense || 0;
    const topCategory = summary?.topCategory || "Belum ada";
    const netCashflow = summary?.netCashflow || 0;

    // Debt reasoning
    const activeDebts = debts?.filter((d: any) => !d.is_settled && d.type === 'hutang') || [];
    const totalDebtAmount = activeDebts.reduce((sum: number, d: any) => sum + d.amount, 0);
    
    // Bills reasoning
    const today = new Date().getDate();
    const upcomingBills = bills?.filter((b: any) => b.is_active && Math.abs(b.due_day - today) <= 3) || [];
    const totalUpcomingBills = upcomingBills.reduce((sum: number, b: any) => sum + b.amount, 0);

    // Investment reasoning
    const totalInvestment = investments?.reduce((sum: number, i: any) => sum + i.current_value, 0) || 0;

    let aiNarrative = "";

    if (transactions?.length === 0) {
      aiNarrative = "Mulai catat transaksimu untuk mendapatkan analisis cerdas di sini.";
    } else {
      const parts = [];
      
      // 1. Expense/Cashflow Insight
      if (totalExpense > 0) {
        parts.push(`Fokus utama bulan ini adalah menjaga pengeluaran di kategori **${topCategory}**. `);
      }

      // 2. Critical Alerts (Bills/Debt)
      if (upcomingBills.length > 0) {
        parts.push(`Kamu punya tagihan yang akan datang senilai **Rp${totalUpcomingBills.toLocaleString('id-ID')}**. Pastikan saldo lancar cukup agar tidak menunggak.`);
      }

      if (totalDebtAmount > (totalInvestment * 2)) {
        parts.push(`Rasio hutangmu terhadap aset investasi terlihat cukup tinggi. Pertimbangkan untuk mereview kembali prioritas pengeluaran.`);
      }

      // 3. Positive Reinforcement
      if (netCashflow > 0 && totalInvestment > 0) {
        parts.push(`Bagus! *Cashflow* positifmu bisa dialokasikan untuk memperkuat portofolio investasi atau melunasi hutang lebih awal.`);
      }

      aiNarrative = parts.join(" ") || "Keuanganmu terlihat stabil. Terus pantau pengeluaran harianmu agar tetap sesuai anggaran.";
    }

    return NextResponse.json({
      narrative: aiNarrative,
      timestamp: new Date().toISOString(),
      isAiGenerated: false,
    });
  } catch (error) {
    console.error("Insights AI Error:", error);
    return NextResponse.json({ error: "Failed to generate insights" }, { status: 500 });
  }
}

import { createClient } from "@/lib/supabase/server";
import { NextResponse } from "next/server";

export async function POST(req: Request) {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();

  if (!user) {
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
  }

  try {
    const { investments } = await req.json();

    if (!Array.isArray(investments) || investments.length === 0) {
      return NextResponse.json({ error: "No valid investments provided" }, { status: 400 });
    }

    const payload = investments.map(inv => ({
      user_id: user.id,
      name: inv.name,
      type: inv.type,
      symbol: inv.symbol || null,
      amount: Number(inv.amount || 0),
      total_invested: Number(inv.total_invested || 0),
      current_value: Number(inv.current_value || 0),
    }));

    const { data, error } = await supabase
      .from("investments")
      .insert(payload)
      .select();

    if (error) throw error;

    return NextResponse.json({ message: "Import success", data });
  } catch (error: any) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

import { createClient } from "@/lib/supabase/server";
import { NextResponse } from "next/server";
import { fetchAssetPrice } from "@/lib/finance-api";

export async function POST() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  // 1. Fetch investments that have a symbol
  const { data: investments, error } = await supabase
    .from("investments")
    .select("*")
    .eq("user_id", user.id)
    .not("symbol", "is", null)
    .neq("symbol", "");

  if (error) return NextResponse.json({ error: error.message }, { status: 500 });
  if (!investments || investments.length === 0) {
    return NextResponse.json({ message: "No assets with symbols found to sync.", updated: 0 });
  }

  let updatedCount = 0;
  const errors: any[] = [];

  // Exchange rate placeholder (Ideal: fetch dynamic USD-IDR rate if needed)
  const EXCHANGE_RATE_USD_IDR = 16000; 

  // 2. Process each investment
  for (const asset of investments) {
    if (!asset.symbol || !asset.amount) continue;

    const result = await fetchAssetPrice(asset.symbol, asset.type);
    
    if (result.success) {
      let finalPrice = result.price;
      
      // Convert to IDR if the raw price from Yahoo is in USD
      // This happens often for Kripto (e.g., BTC-USD)
      if (result.currency === 'USD') {
         finalPrice = result.price * EXCHANGE_RATE_USD_IDR;
      }

      // Calculate new value
      const newValue = finalPrice * asset.amount;

      // Update Database
      const { error: updateError } = await supabase
        .from("investments")
        .update({ 
          current_value: newValue,
          // We could optionally store 'last_synced_at' on the table later
        })
        .eq("id", asset.id);

      if (updateError) {
        errors.push({ symbol: asset.symbol, error: updateError.message });
      } else {
        updatedCount++;
      }
    } else {
      errors.push({ symbol: asset.symbol, error: result.error });
    }
  }

  return NextResponse.json({
    message: `Successfully synced ${updatedCount} assets.`,
    updated: updatedCount,
    errors: errors.length > 0 ? errors : undefined,
  }, { status: 200 });
}

import { createClient } from "@/lib/supabase/server";
import { NextResponse } from "next/server";

export async function GET() {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  // Try to get existing profile
  const { data, error } = await supabase
    .from("user_profiles")
    .select("*")
    .eq("user_id", user.id)
    .maybeSingle();

  if (error) return NextResponse.json({ error: error.message }, { status: 500 });

  // Return profile or default values
  return NextResponse.json(data || { 
    payday_day: null, 
    primary_wallet_id: null,
    show_decimals: false,
    accent_color: 'wise-green'
  });
}

export async function PUT(request: Request) {
  const supabase = await createClient();
  const { data: { user } } = await supabase.auth.getUser();
  if (!user) return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const body = await request.json();
  const { payday_day, primary_wallet_id, show_decimals, accent_color, showDecimals, accentColor } = body;

  // Map camelCase to snake_case for backward compatibility and frontend consistency
  const finalShowDecimals = show_decimals !== undefined ? show_decimals : showDecimals;
  const finalAccentColor = accent_color !== undefined ? accent_color : accentColor;

  // Prepare update object
  const updateData: any = {
    user_id: user.id,
    updated_at: new Date().toISOString(),
  };

  if (payday_day !== undefined) {
    // Validate payday_day
    if (payday_day !== null) {
      const day = Number(payday_day);
      if (isNaN(day) || day < 1 || day > 31) {
        return NextResponse.json({ error: "Tanggal gajian harus antara 1-31" }, { status: 400 });
      }
    }
    updateData.payday_day = payday_day;
  }

  if (primary_wallet_id !== undefined) {
    // Validate primary_wallet_id belongs to user if provided
    if (primary_wallet_id) {
      const { data: wallet } = await supabase
        .from("wallets")
        .select("id")
        .eq("id", primary_wallet_id)
        .eq("user_id", user.id)
        .maybeSingle();

      if (!wallet) {
        return NextResponse.json({ error: "Dompet tidak ditemukan" }, { status: 404 });
      }
    }
    updateData.primary_wallet_id = primary_wallet_id;
  }

  if (finalShowDecimals !== undefined) {
    updateData.show_decimals = finalShowDecimals;
  }

  if (finalAccentColor !== undefined) {
    updateData.accent_color = finalAccentColor;
  }

  // Upsert the profile
  const { data, error } = await supabase
    .from("user_profiles")
    .upsert(updateData, { onConflict: "user_id" })
    .select()
    .single();

  if (error) return NextResponse.json({ error: error.message }, { status: 500 });
  return NextResponse.json(data);
}

import { Button } from "@/components/ui/button";
import Link from "next/link";
import { AlertCircle, ArrowLeft } from "lucide-react";
