"use client";

import { useState, useEffect } from "react";
import { PieChart, Info } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { 
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter 
} from "@/components/ui/dialog";
import { CurrencyInput } from "@/components/ui/currency-input";
import { Budget } from "./budget-card";

interface BudgetFormModalProps {
  open: boolean;
  onClose: () => void;
  onSuccess: () => void;
  budget?: Budget | null;
}

export function BudgetFormModal({ open, onClose, onSuccess, budget }: BudgetFormModalProps) {
  const [category, setCategory] = useState("");
  const [amount, setAmount] = useState<number>(0);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const [categoriesList, setCategoriesList] = useState<{id: string, name: string}[]>([]);

  useEffect(() => {
    fetch("/api/categories")
      .then(r => r.json())
      .then(d => setCategoriesList(Array.isArray(d) ? d : []))
      .catch(e => console.error(e));
  }, []);

  useEffect(() => {
    if (budget) {
      setCategory(budget.category);
      setAmount(budget.amount);
    } else {
      setCategory("");
      setAmount(0);
    }
    setError("");
  }, [budget, open]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!category || !amount) {
      setError("Kategori dan limit wajib diisi.");
      return;
    }

    setIsLoading(true);
    setError("");

    try {
      const currentMonth = new Date().toISOString().substring(0, 7);
      const url = budget ? `/api/budgets/${budget.id}` : "/api/budgets";
      const method = budget ? "PUT" : "POST";
      
      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          category,
          amount: amount,
          month: currentMonth
        }),
      });

      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.error || "Gagal menyimpan anggaran");
      }

      onSuccess();
      onClose();
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Terjadi kesalahan sistem.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={(o) => !o && onClose()}>
      <DialogContent className="sm:max-w-md rounded-[2rem] sm:rounded-[2.5rem] border-border/40 p-6 sm:p-8 max-h-[90vh] overflow-y-auto custom-scrollbar">
        <DialogHeader>
          <div 
            className="w-12 h-12 rounded-2xl flex items-center justify-center mb-4 mx-auto md:mx-0 shadow-sm"
            style={{ backgroundColor: `var(--primary-color, rgba(159, 232, 112, 0.15))`, color: "var(--primary-color, #9fe870)" }}
          >
            <PieChart className="w-6 h-6 text-primary" />
          </div>
          <DialogTitle className="text-2xl font-black tracking-tight text-center md:text-left">
            {budget ? "Edit Limit Anggaran" : "Buat Anggaran Baru"}
          </DialogTitle>
          <DialogDescription className="text-muted-foreground font-medium text-center md:text-left">
            Tetapkan batas pengeluaran untuk kategori tertentu.
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-6 pt-4">
          <div className="space-y-4">
            <div className="space-y-2">
              <Label className="text-xs font-black uppercase tracking-widest ml-1">Kategori Pengeluaran</Label>
              {categoriesList.length > 0 ? (
                <Select value={category} onValueChange={setCategory} disabled={!!budget}>
                  <SelectTrigger className="h-14 rounded-2xl border-border/40 px-4 w-full font-semibold">
                    <SelectValue placeholder="Pilih kategori" />
                  </SelectTrigger>
                  <SelectContent className="rounded-2xl border-border/40">
                    {categoriesList.map((c) => (
                      <SelectItem key={c.id} value={c.name} className="rounded-xl cursor-pointer">
                        {c.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              ) : (
                <div className="h-14 rounded-2xl border border-dashed border-border/60 flex items-center justify-between px-4 bg-muted/20">
                  <span className="text-sm font-semibold text-muted-foreground mr-2 truncate">Belum ada Kategori</span>
                  <a href="/dashboard/categories" className="text-xs font-bold text-primary shrink-0 hover:underline">Tambah →</a>
                </div>
              )}
              {budget && <p className="text-[10px] text-muted-foreground ml-2">Kategori tidak dapat diubah pada anggaran yang sudah dibuat. Buat anggaran baru jika perlu.</p>}
            </div>

            <div className="space-y-2">
              <Label className="text-xs font-black uppercase tracking-widest ml-1">Limit Bulanan</Label>
              <CurrencyInput
                value={amount}
                onChange={setAmount}
                required
                className="h-14 text-xl font-bold"
              />
            </div>
          </div>

          {error && (
            <div className="flex items-center gap-2 p-3 rounded-xl bg-expense/10 text-expense text-xs font-bold">
              <Info className="w-4 h-4" /> {error}
            </div>
          )}

          <DialogFooter className="pt-2 sm:pt-4 flex flex-col sm:flex-row gap-2 sm:gap-0">
            <Button 
              type="button" 
              variant="ghost" 
              onClick={onClose}
              className="rounded-2xl h-12 px-6 font-bold w-full sm:w-auto order-last sm:order-first"
            >
              Batal
            </Button>
            <Button 
              type="submit" 
              disabled={isLoading || !category || !amount}
              className="rounded-2xl h-12 px-8 font-black bg-primary text-primary-foreground hover:brightness-110 shadow-lg active:scale-95 transition-all w-full sm:w-auto"
            >
              {isLoading ? "Menyimpan..." : budget ? "Simpan Perubahan" : "Buat Anggaran"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import { useState, useEffect, useCallback, useMemo } from "react";
import { createClient } from "@/lib/supabase/client";
import { useCategories } from "@/hooks/use-categories";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Plus, Target, Loader2, Pencil, Trash2, AlertTriangle, Circle, ChevronLeft, ChevronRight } from "lucide-react";
import Link from "next/link";
import { useFormatCurrency } from "@/hooks/use-format-currency";

interface Budget {
  id: string;
  category: string;
  amount: number;
  month: string;
}

interface BudgetSectionProps {
  transactions: any[];
  itemsPerPage?: number;
}

const ITEMS_PER_PAGE = 6; // 2x3 grid


function formatRupiah(value: string) {
  const n = value.replace(/\D/g, "");
  if (!n) return "";
  return new Intl.NumberFormat("id-ID", {
    style: "currency", currency: "IDR", minimumFractionDigits: 0,
  }).format(parseInt(n, 10));
}

//  Budget Card 
function BudgetCard({
  budget,
  spent,
  onEdit,
  onDelete,
}: {
  budget: Budget;
  spent: number;
  onEdit: (b: Budget) => void;
  onDelete: (b: Budget) => void;
}) {
  const { formatCurrency } = useFormatCurrency();
  const pct = budget.amount > 0 ? Math.min(Math.round((spent / budget.amount) * 100), 100) : 0;
  const barColor =
    pct >= 90 ? "bg-destructive" :
    pct >= 75 ? "bg-chart-5" :
    "bg-success";
  const textColor =
    pct >= 90 ? "text-destructive" :
    pct >= 75 ? "text-chart-5" :
    "text-success";

  return (
    <div className="group relative rounded-2xl bg-card/60 backdrop-blur-sm border border-border/40 p-5 hover:shadow-md hover:border-border/60 transition-all duration-200">
      {/* Actions (hover) */}
      <div className="absolute top-3 right-3 flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
        <Button variant="ghost" size="icon" className="h-7 w-7 text-muted-foreground hover:text-foreground" onClick={() => onEdit(budget)}>
          <Pencil className="w-3.5 h-3.5" />
        </Button>
        <Button variant="ghost" size="icon" className="h-7 w-7 text-muted-foreground hover:text-destructive" onClick={() => onDelete(budget)}>
          <Trash2 className="w-3.5 h-3.5" />
        </Button>
      </div>

      {/* Category */}
      <p className="font-semibold text-sm mb-3 pr-16 truncate">{budget.category}</p>

      {/* Progress Bar */}
      <div className="h-2 rounded-full bg-muted/60 overflow-hidden mb-3">
        <div
          className={`h-full rounded-full transition-all duration-500 ${barColor}`}
          style={{ width: `${pct}%` }}
        />
      </div>

      {/* Amounts */}
      <div className="flex items-center justify-between">
        <div>
          <p className="text-xs text-muted-foreground">Terpakai</p>
          <p className={`text-sm font-bold ${textColor}`}>{formatCurrency(spent)}</p>
        </div>
        <div className="text-right">
          <p className="text-xs text-muted-foreground">Anggaran</p>
          <p className="text-sm font-medium">{formatCurrency(budget.amount)}</p>
        </div>
      </div>

      <div className={`mt-3 text-right text-xs font-semibold flex items-center justify-end gap-1.5 ${textColor}`}>
        {pct >= 100 ? <AlertTriangle className="w-3 h-3" /> : <Circle className="w-2.5 h-2.5 fill-current" />}
        {pct}% {pct >= 100 ? "Melebihi!" : pct >= 90 ? "Hampir habis" : pct >= 75 ? "Waspada" : "Aman"}
      </div>
    </div>
  );
}

//  Main Component 
export function BudgetSection({ transactions }: BudgetSectionProps) {
  const { formatCurrency } = useFormatCurrency();
  const [budgets, setBudgets] = useState<Budget[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [currentPage, setCurrentPage] = useState(1);

  // Form state
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingBudget, setEditingBudget] = useState<Budget | null>(null);
  const [formCategory, setFormCategory] = useState("");
  const [formAmount, setFormAmount] = useState("");

  // Delete dialog
  const [deletingBudget, setDeletingBudget] = useState<Budget | null>(null);
  const [isDeleting, setIsDeleting] = useState(false);

  const { expenseCategories, loading: catLoading } = useCategories();

  const supabase = createClient();
  const currentMonth = new Date().toISOString().substring(0, 7);

  //  Fetch 
  const fetchBudgets = useCallback(async () => {
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;
      const { data, error } = await supabase
        .from("budgets").select("*")
        .eq("user_id", user.id).eq("month", currentMonth)
        .order("category", { ascending: true });
      if (error) throw error;
      setBudgets(data || []);
    } catch (error) {
      console.error("Error fetching budgets:", error);
    } finally {
      setLoading(false);
    }
  }, [supabase, currentMonth]);

  useEffect(() => { fetchBudgets(); }, [fetchBudgets]);

  //  Pagination 
  const totalPages = Math.ceil(budgets.length / ITEMS_PER_PAGE);
  const paginatedBudgets = useMemo(() => {
    const start = (currentPage - 1) * ITEMS_PER_PAGE;
    return budgets.slice(start, start + ITEMS_PER_PAGE);
  }, [budgets, currentPage]);

  //  Helpers 
  const getSpent = (cat: string) =>
    transactions.filter(t => t.type === "expense" && t.category === cat)
      .reduce((sum, t) => sum + Number(t.amount), 0);

  const openAdd = () => {
    setEditingBudget(null);
    setFormCategory("");
    setFormAmount("");
    setIsFormOpen(true);
  };

  const openEdit = (b: Budget) => {
    setEditingBudget(b);
    setFormCategory(b.category);
    setFormAmount(String(b.amount));
    setIsFormOpen(true);
  };

  const closeForm = () => {
    setIsFormOpen(false);
    setEditingBudget(null);
    setFormCategory("");
    setFormAmount("");
  };

  //  Save (Add / Edit) 
  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setSaving(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("No user");

      const parsedAmount = parseInt(formAmount.replace(/\D/g, ""), 10);
      if (isNaN(parsedAmount) || parsedAmount <= 0) return;

      if (editingBudget) {
        // Edit existing
        await supabase.from("budgets")
          .update({ amount: parsedAmount, category: formCategory })
          .eq("id", editingBudget.id);
      } else {
        // Add new  if same category exists this month, update instead
        const existing = budgets.find(b => b.category === formCategory);
        if (existing) {
          await supabase.from("budgets").update({ amount: parsedAmount }).eq("id", existing.id);
        } else {
          await supabase.from("budgets").insert({
            user_id: user.id, category: formCategory, amount: parsedAmount, month: currentMonth,
          });
        }
      }
      await fetchBudgets();
      closeForm();
    } catch (err) {
      console.error("Error saving budget:", err);
    } finally {
      setSaving(false);
    }
  };

  //  Delete 
  const handleDelete = async () => {
    if (!deletingBudget) return;
    setIsDeleting(true);
    try {
      await supabase.from("budgets").delete().eq("id", deletingBudget.id);
      await fetchBudgets();
      // Fix page if now empty
      const newTotal = Math.ceil((budgets.length - 1) / ITEMS_PER_PAGE);
      if (currentPage > newTotal && newTotal > 0) setCurrentPage(newTotal);
    } catch (err) {
      console.error("Error deleting budget:", err);
    } finally {
      setIsDeleting(false);
      setDeletingBudget(null);
    }
  };

  //  Loading skeleton 
  if (loading) {
    return (
      <Card className="shadow-sm border-0 bg-card/60 backdrop-blur-xl animate-pulse h-40">
        <CardContent className="h-full flex items-center justify-center text-muted-foreground text-sm">
          Memuat anggaran...
        </CardContent>
      </Card>
    );
  }

  return (
    <>
      <Card className="shadow-sm border-0 bg-card/60 backdrop-blur-xl overflow-hidden">
        {/* Header */}
        <CardHeader className="bg-muted/30 pb-4 flex flex-row items-center justify-between">
          <div>
            <CardTitle className="text-xl flex items-center gap-2">
              <Target className="w-5 h-5 text-primary" /> Anggaran Bulanan
            </CardTitle>
            <CardDescription>
              {budgets.length} anggaran aktif  Bulan Ini
            </CardDescription>
          </div>
          <Button variant="default" size="sm" onClick={openAdd} className="h-9 gap-1 hover:bg-primary/70">
            <Plus className="w-4 h-4" /> Set Anggaran
          </Button>
        </CardHeader>

        <CardContent className="p-5">
          {budgets.length === 0 ? (
            <div className="text-center py-10 text-muted-foreground bg-muted/20 rounded-xl border border-dashed border-border/50 text-sm font-medium">
              Belum ada target anggaran. Klik <strong>"Set Anggaran"</strong> untuk memulai!
            </div>
          ) : (
            <>
              {/* Grid */}
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {paginatedBudgets.map((b) => (
                  <BudgetCard
                    key={b.id}
                    budget={b}
                    spent={getSpent(b.category)}
                    onEdit={openEdit}
                    onDelete={setDeletingBudget}
                  />
                ))}
              </div>

              {/* Pagination */}
              {totalPages > 1 && (
                <div className="flex items-center justify-between mt-5 pt-4 border-t border-border/30">
                  <p className="text-sm text-muted-foreground">
                    Halaman {currentPage} dari {totalPages}
                  </p>
                  <div className="flex items-center gap-2">
                    <Button variant="outline" size="sm" className="h-8 px-3 rounded-lg"
                      onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                      disabled={currentPage === 1}>
                      <ChevronLeft className="w-4 h-4 mr-1" /> Sebelumnya
                    </Button>
                    <Button variant="outline" size="sm" className="h-8 px-3 rounded-lg"
                      onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                      disabled={currentPage === totalPages}>
                      Selanjutnya <ChevronRight className="w-4 h-4 ml-1" />
                    </Button>
                  </div>
                </div>
              )}
            </>
          )}
        </CardContent>
      </Card>

      {/*  Add / Edit Dialog  */}
      <Dialog open={isFormOpen} onOpenChange={(open) => { if (!open) closeForm(); }}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>{editingBudget ? "Edit Anggaran" : "Set Anggaran Baru"}</DialogTitle>
            <DialogDescription>
              {editingBudget
                ? "Ubah kategori atau nominal anggaran."
                : "Tentukan batas pengeluaran untuk sebuah kategori bulan ini."}
            </DialogDescription>
          </DialogHeader>

          <form onSubmit={handleSave} className="space-y-4 pt-2">
            <div className="space-y-2">
              <Label htmlFor="dlg-category">Kategori</Label>
              <Select
                value={formCategory}
                onValueChange={setFormCategory}
                required
                disabled={catLoading || expenseCategories.length === 0}
              >
                <SelectTrigger id="dlg-category" className="h-10">
                  <SelectValue placeholder={catLoading ? "Memuat..." : "Pilih kategori"} />
                </SelectTrigger>
                <SelectContent>
                  {expenseCategories.map((cat) => (
                    <SelectItem key={cat.id} value={cat.name}>
                      {cat.icon} {cat.name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
              {!catLoading && expenseCategories.length === 0 && (
                <p className="text-xs text-amber-600 dark:text-amber-400 flex items-center gap-1">
                  <AlertTriangle className="w-3 h-3" /> Belum ada kategori.{" "}
                  <Link href="/dashboard/categories" className="font-semibold underline flex items-center gap-1">
                    Tambah sekarang <ChevronRight className="w-3 h-3" />
                  </Link>
                </p>
              )}
            </div>

            <div className="space-y-2">
              <Label htmlFor="dlg-amount">Batas Nominal (Rp)</Label>
              <Input
                id="dlg-amount"
                value={formatRupiah(formAmount)}
                onChange={(e) => setFormAmount(e.target.value)}
                placeholder="Rp 0"
                required
                className="h-10"
              />
            </div>

            <DialogFooter className="gap-2 pt-2">
              <Button type="button" variant="outline" onClick={closeForm}>Batal</Button>
              <Button
                type="submit"
                className="gradient-primary text-secondary"
                disabled={saving || !formCategory || !formAmount}
              >
                {saving && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                {saving ? "Menyimpan..." : editingBudget ? "Simpan Perubahan" : "Simpan Anggaran"}
              </Button>
            </DialogFooter>
          </form>
        </DialogContent>
      </Dialog>

      {/*  Delete Confirmation  */}
      <Dialog open={!!deletingBudget} onOpenChange={(open) => { if (!open) setDeletingBudget(null); }}>
        <DialogContent className="sm:max-w-sm">
          <DialogHeader>
            <DialogTitle>Hapus Anggaran</DialogTitle>
            <DialogDescription>
              Hapus anggaran <strong>{deletingBudget?.category}</strong>? Tindakan ini tidak dapat dibatalkan.
            </DialogDescription>
          </DialogHeader>
          <DialogFooter className="gap-2">
            <Button variant="outline" onClick={() => setDeletingBudget(null)} disabled={isDeleting}>Batal</Button>
            <Button variant="destructive" onClick={handleDelete} disabled={isDeleting}>
              {isDeleting ? "Menghapus..." : "Hapus"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import { createClient } from "@/lib/supabase/client";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Target, ChevronRight } from "lucide-react";

interface Budget { id: string; category: string; amount: number; }

function formatK(n: number) {
  if (n >= 1_000_000) return `Rp ${(n / 1_000_000).toFixed(1)}jt`;
  if (n >= 1_000) return `Rp ${Math.round(n / 1_000)}rb`;
  return `Rp ${n}`;
}

interface Props {
  transactions: any[];
  onSeeAll: () => void;
}

export function BudgetSnapshot({ transactions, onSeeAll }: Props) {
  const [budgets, setBudgets] = useState<Budget[]>([]);
  const [loading, setLoading] = useState(true);
  const supabase = createClient();
  const currentMonth = new Date().toISOString().substring(0, 7);

  const fetchBudgets = useCallback(async () => {
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;
      const { data } = await supabase.from("budgets").select("*")
        .eq("user_id", user.id).eq("month", currentMonth)
        .order("category", { ascending: true }).limit(4);
      setBudgets(data || []);
    } catch { /* silently fail */ }
    finally { setLoading(false); }
  }, [supabase, currentMonth]);

  useEffect(() => { fetchBudgets(); }, [fetchBudgets]);

  const getSpent = (cat: string) =>
    transactions.filter(t => t.type === "expense" && t.category === cat)
      .reduce((s, t) => s + Number(t.amount), 0);

  if (loading) {
    return (
      <Card className="shadow-sm border-0 bg-card/60 backdrop-blur-xl animate-pulse h-32" />
    );
  }

  return (
    <Card className="shadow-sm border-0 bg-card/60 backdrop-blur-xl overflow-hidden">
      <CardHeader className="bg-muted/30 pb-3 flex flex-row items-center justify-between">
        <CardTitle className="text-base flex items-center gap-2">
          <Target className="w-4 h-4 text-primary" /> Anggaran Bulanan
        </CardTitle>
        <Button variant="ghost" size="sm" className="text-xs h-7 gap-1 text-muted-foreground hover:text-foreground" onClick={onSeeAll}>
          <span>Lihat Semua</span>
          <ChevronRight className="w-3 h-3" />
        </Button>
      </CardHeader>

      <CardContent className="p-4 space-y-3">
        {budgets.length === 0 ? (
          <p className="text-xs text-muted-foreground text-center py-4">
            Belum ada anggaran. Atur di tab Anggaran!
          </p>
        ) : (
          budgets.map((b) => {
            const spent = getSpent(b.category);
            const pct = b.amount > 0 ? Math.min(Math.round((spent / b.amount) * 100), 100) : 0;
            const barColor = pct >= 90 ? "bg-rose-500" : pct >= 75 ? "bg-amber-500" : "bg-emerald-500";
            const textColor = pct >= 90 ? "text-rose-600 dark:text-rose-400" : pct >= 75 ? "text-amber-600 dark:text-amber-400" : "text-emerald-600 dark:text-emerald-400";

            return (
              <div key={b.id} className="space-y-1.5">
                <div className="flex items-center justify-between">
                  <span className="text-xs font-medium truncate max-w-[120px]">{b.category}</span>
                  <span className={`text-xs font-bold ${textColor}`}>{pct}%</span>
                </div>
                <div className="h-1.5 rounded-full bg-muted/60 overflow-hidden">
                  <div className={`h-full rounded-full transition-all duration-500 ${barColor}`} style={{ width: `${pct}%` }} />
                </div>
                <div className="flex justify-between text-xs text-muted-foreground">
                  <span>{formatK(spent)}</span>
                  <span>{formatK(b.amount)}</span>
                </div>
              </div>
            );
          })
        )}
      </CardContent>
    </Card>
  );
}

"use client";

import { useMemo, useState, useEffect, useCallback } from "react";
import type { Transaction } from "@/components/finance/transaction-form";
import { createClient } from "@/lib/supabase/client";
import { useFormatCurrency } from "@/hooks/use-format-currency";

interface CategoryProgress {
  name: string;
  spent: number;
  total: number;
  colorClass: string;
}

interface DashboardProgressCardProps {
  transactions: Transaction[];
}

export function DashboardProgressCard({ transactions }: DashboardProgressCardProps) {
  const { formatCurrency } = useFormatCurrency();
  const [budgets, setBudgets] = useState<any[]>([]);
  const supabase = createClient();
  
  const today = new Date();
  const day = today.getDate();
  const daysInMonth = new Date(today.getFullYear(), today.getMonth() + 1, 0).getDate();
  
  const fetchBudgets = useCallback(async () => {
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;
      const currentMonth = new Date().toISOString().substring(0, 7);
      const { data } = await supabase.from("budgets").select("*")
        .eq("user_id", user.id)
        .eq("month", currentMonth);
      setBudgets(data || []);
    } catch { /* silent */ }
  }, [supabase]);

  useEffect(() => { fetchBudgets(); }, [fetchBudgets]);

  
  const categoryExpenses = useMemo(() => {
    const currentMonthTx = transactions.filter(t => {
      const txDate = new Date(t.date);
      return txDate.getMonth() === today.getMonth() && 
             txDate.getFullYear() === today.getFullYear() &&
             t.type === 'expense';
    });

    const expensesMap = currentMonthTx.reduce((acc, t) => {
      acc[t.category] = (acc[t.category] || 0) + Math.abs(t.amount);
      return acc;
    }, {} as Record<string, number>);

    return expensesMap;
  }, [transactions, today.getMonth(), today.getFullYear()]);

  // Map into display data, sorting by highest spent
  const topCategories = useMemo(() => {

    const colors = ["bg-chart-1", "bg-chart-2", "bg-chart-3", "bg-chart-4", "bg-chart-5"];
    
    const cats = Object.entries(categoryExpenses)
      .sort(([, a], [, b]) => b - a)
      .slice(0, 3) // Show top 3
      .map(([name, spent], index) => {
      
        const budgetForCat = budgets.find(b => b.category === name);
        const estimatedBudget = budgetForCat ? Number(budgetForCat.amount) : 1000000; 
        const total = spent > estimatedBudget ? spent * 1.2 : estimatedBudget; 
        
        return {
          name,
          spent,
          total, 
          colorClass: colors[index % colors.length]
        };
      });
      
    
    if (cats.length === 0) {
      return [
        { name: "Belum ada", spent: 0, total: 1000, colorClass: "bg-muted" },
      ];
    }
    
    return cats;
  }, [categoryExpenses]);

  const calculatePercentage = (spent: number, total: number) => {
    if (total === 0) return 0;
    return Math.min(Math.round((spent / total) * 100), 100);
  };

  const getProgressLabel = (spent: number, total: number) => {
    if (total === 0) return "Belum diatur";
    const p = spent / total;
    if (p === 0) return "0 Pengeluaran";
    if (p < 0.5) return "Masih aman";
    if (p < 0.8) return "Hati-hati";
    if (p <= 1) return "Hampir habis";
    return "Melewati batas";
  };

  // Circular progress math
  const progressRatio = day / daysInMonth;
  const circleCircumference = 2 * Math.PI * 24; // r=24
  const strokeDashoffset = circleCircumference - progressRatio * circleCircumference;

  return (
    <div className="bg-white dark:bg-card rounded-[2rem] border border-border/40 p-6 shadow-sm flex flex-col md:flex-row gap-8 items-center mt-6">
      
      {/* Left: Circular Progress for Days */}
      <div className="flex items-center gap-4 shrink-0">
        <div className="relative flex items-center justify-center">
          <svg className="w-20 h-20 transform -rotate-90">
            <circle
              cx="40"
              cy="40"
              r="24"
              className="stone-100"
              strokeWidth="4"
              stroke="currentColor"
              fill="transparent"
              style={{ color: "rgba(100, 116, 139, 0.1)" }}
            />
            <circle
              cx="40"
              cy="40"
              r="24"
              className="text-foreground"
              strokeWidth="4"
              strokeDasharray={circleCircumference}
              strokeDashoffset={strokeDashoffset}
              strokeLinecap="round"
              stroke="currentColor"
              fill="transparent"
            />
          </svg>
          <div className="absolute flex flex-col items-center justify-center">
            <span className="text-[10px] font-bold text-muted-foreground uppercase leading-none">Hari</span>
            <span className="text-xl font-bold leading-none mt-0.5">{day}</span>
          </div>
        </div>
        
        <div>
          <h3 className="font-bold text-foreground">Progres Pengeluaran</h3>
          <p className="text-xs text-muted-foreground">Hari {day} dari {daysInMonth}</p>
        </div>
      </div>

      {/* Right: Linear Progress Bars */}
      <div className="flex-1 w-full space-y-4">
        {topCategories.map((cat, i) => {
          const percentage = calculatePercentage(cat.spent, cat.total);
          const labelDisplay = getProgressLabel(cat.spent, cat.total);
          
          return (
            <div key={i} className="space-y-1.5">
              <div className="flex justify-between items-end">
                <div className="flex items-baseline gap-2">
                  <span className={`text-[10px] sm:text-xs font-bold uppercase tracking-wider ${cat.colorClass.replace('bg-', 'text-')}`}>
                    {cat.name}
                  </span>
                  <span className="text-[10px] text-muted-foreground">{labelDisplay}</span>
                </div>
                <div className="flex items-center gap-1.5">
                  <span className="text-[10px] text-muted-foreground">{formatCurrency(cat.spent)}</span>
                  <span className="text-[10px] font-bold">{cat.spent > cat.total && cat.total !== 1000 ? Math.round((cat.spent/cat.total)*100) : percentage}%</span>
                </div>
              </div>
              <div className="h-2 w-full bg-muted/50 rounded-full overflow-hidden">
                <div 
                  className={`h-full ${cat.colorClass} rounded-full`}
                  style={{ width: `${Math.min(cat.spent > cat.total && cat.total !== 1000 ? 100 : percentage, 100)}%` }}
                />
              </div>
            </div>
          );
        })}
      </div>

    </div>
  );
}

"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import { Bell, AlertTriangle, CheckCircle2, Info, X, ChevronRight } from "lucide-react";
import { Button } from "@/components/ui/button";
import { useFormatCurrency } from "@/hooks/use-format-currency";
import Link from "next/link";

interface Notification {
  id: string;
  type: "danger" | "warning" | "success" | "info";
  title: string;
  description: string;
  href?: string;
  time: string;
}

export function NotificationBell() {
  const { formatCurrency } = useFormatCurrency();
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isOpen, setIsOpen] = useState(false);
  const [loading, setLoading] = useState(true);
  const containerRef = useRef<HTMLDivElement>(null);

  const generateNotifications = useCallback(async () => {
    try {
      const [billsRes, budgetsRes, txRes] = await Promise.all([
        fetch("/api/recurring-bills"),
        fetch("/api/budgets"),
        fetch(`/api/transactions?_t=${Date.now()}`, { cache: "no-store" }),
      ]);

      const [bills, budgets, transactions] = await Promise.all([
        billsRes.ok ? billsRes.json() : [],
        budgetsRes.ok ? budgetsRes.json() : [],
        txRes.ok ? txRes.json() : [],
      ]);

      const items: Notification[] = [];
      const today = new Date();
      const currentDay = today.getDate();
      const currentMonth = today.toISOString().substring(0, 7);
      const now = today.toLocaleTimeString("id-ID", { hour: "2-digit", minute: "2-digit" });

      // Bills due soon
      if (Array.isArray(bills)) {
        bills.forEach((bill: { id: string; name: string; amount: number; due_day: number }) => {
          const daysUntilDue = bill.due_day - currentDay;
          if (daysUntilDue >= 0 && daysUntilDue <= 3) {
            items.push({
              id: `bill-${bill.id}`,
              type: daysUntilDue === 0 ? "danger" : "warning",
              title: daysUntilDue === 0
                ? `${bill.name} jatuh tempo hari ini!`
                : `${bill.name} jatuh tempo ${daysUntilDue} hari lagi`,
              description: `Tagihan ${formatCurrency(bill.amount)} harus segera dibayar.`,
              href: "/dashboard/bills",
              time: now,
            });
          }
        });
      }

      // Budget warnings
      if (Array.isArray(budgets) && Array.isArray(transactions)) {
        const monthlyExpenses = transactions.filter(
          (t: { type: string; date: string }) => t.type === "expense" && t.date.startsWith(currentMonth)
        );
        budgets.forEach((budget: { id: string; category: string; amount: number }) => {
          const spent = monthlyExpenses
            .filter((t: { category: string }) => t.category === budget.category)
            .reduce((s: number, t: { amount: number }) => s + Number(t.amount), 0);
          const pct = budget.amount > 0 ? Math.round((spent / budget.amount) * 100) : 0;
          if (pct >= 80) {
            items.push({
              id: `budget-${budget.id}`,
              type: pct >= 90 ? "danger" : "warning",
              title: `Budget ${budget.category} ${pct}%`,
              description: `${formatCurrency(spent)} dari ${formatCurrency(budget.amount)} sudah terpakai.`,
              href: "/dashboard/budgets",
              time: now,
            });
          }
        });
      }

      // Good savings
      if (Array.isArray(transactions)) {
        const monthlyTx = transactions.filter((t: { date: string }) => t.date.startsWith(currentMonth));
        const income = monthlyTx
          .filter((t: { type: string }) => t.type === "income")
          .reduce((s: number, t: { amount: number }) => s + Number(t.amount), 0);
        const expense = monthlyTx
          .filter((t: { type: string }) => t.type === "expense")
          .reduce((s: number, t: { amount: number }) => s + Number(t.amount), 0);

        if (income > 0 && (income - expense) / income >= 0.2) {
          items.push({
            id: "savings-good",
            type: "success",
            title: "Keuanganmu sehat bulan ini! 🎉",
            description: `Kamu menyisihkan ${Math.round(((income - expense) / income) * 100)}% dari pemasukan.`,
            time: now,
          });
        }
      }

      if (items.length === 0) {
        items.push({
          id: "no-alert",
          type: "info",
          title: "Semua terkendali!",
          description: "Tidak ada peringatan saat ini. Keuanganmu aman!",
          time: now,
        });
      }

      setNotifications(items);
    } catch {
      /* silent */
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { generateNotifications(); }, [generateNotifications]);

  // Close when clicking outside
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const alertCount = notifications.filter((n) => n.type === "danger" || n.type === "warning").length;

  const iconMap = {
    danger: <AlertTriangle className="w-3.5 h-3.5 text-red-500" />,
    warning: <Bell className="w-3.5 h-3.5 text-amber-500" />,
    success: <CheckCircle2 className="w-3.5 h-3.5 text-emerald-500" />,
    info: <Info className="w-3.5 h-3.5 text-blue-500" />,
  };

  const bgMap = {
    danger: "bg-red-50 dark:bg-red-950/20",
    warning: "bg-amber-50 dark:bg-amber-950/20",
    success: "bg-emerald-50 dark:bg-emerald-950/20",
    info: "bg-blue-50 dark:bg-blue-950/20",
  };

  return (
    <div ref={containerRef} className="relative">
      <Button
        variant="ghost"
        size="icon"
        onClick={() => setIsOpen(!isOpen)}
        className="relative shrink-0 w-12 h-12 rounded-full bg-white dark:bg-card border border-border/10 hover:border-primary/30 transition-all"
      >
        <Bell className="w-[18px] h-[18px]" />
        {alertCount > 0 && (
          <span className="absolute -top-0.5 -right-0.5 w-5 h-5 bg-red-500 text-white text-[9px] font-black rounded-full flex items-center justify-center ring-2 ring-background animate-in zoom-in duration-200">
            {alertCount}
          </span>
        )}
      </Button>

      {/* Dropdown */}
      {isOpen && (
