            <p className="text-[10px] font-black text-muted-foreground/60 text-center uppercase tracking-widest" style={{ fontFeatureSettings: '"calt"' }}>
              Notifikasi otomatis berdasarkan data keuanganmu
            </p>
          </div>
        </div>
      )}
    </div>
  );
