  plan_id: string;
  status: string;
  interval: string;
  amount: number;
  expires_at: string | null;
}

const tierConfig: Record<string, {
  name: string;
  label: string;
  gradient: string;
  textColor: string;
  labelBg: string;
  icon: typeof Crown;
  description: string;
}> = {
  free: {
