    label: "Paket Gratis",
    gradient: "from-slate-100 to-slate-200 dark:from-slate-800 dark:to-slate-900",
    textColor: "text-slate-700 dark:text-slate-200",
    labelBg: "bg-slate-500/10 text-slate-600 dark:text-slate-300",
    icon: Sparkles,
    description: "Fitur dasar untuk mulai mencatat keuangan.",
  },
  plus: {
    name: "Plus",
    label: "Ngaturin PLUS",
    gradient: "from-[#9fe870] to-[#cdffad]",
    textColor: "text-[#163300]",
    labelBg: "bg-[#163300]/10 text-[#163300]",
    icon: Sparkles,
    description: "Kebebasan tanpa batas untuk keuanganmu.",
  },
  pro: {
    name: "Pro",
    label: "Ngaturin PRO",
    gradient: "from-[#0e0f0c] to-[#2a2d28]",
    textColor: "text-white",
    labelBg: "bg-white/20 text-white",
    icon: Crown,
    description: "Asisten cerdas untuk keuangan optimal.",
  },
};

export function SubscriptionCard() {
  const [subscription, setSubscription] = useState<Subscription | null>(null);
  const [loading, setLoading] = useState(true);
  const [userName, setUserName] = useState("User");

  const fetchSubscription = useCallback(async () => {
    try {
      const supabase = createClient();
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      if (user.user_metadata?.full_name) {
        setUserName(user.user_metadata.full_name);
      } else if (user.email) {
        setUserName(user.email.split("@")[0]);
      }

      const { data } = await supabase
        .from("subscriptions")
        .select("*")
        .eq("user_id", user.id)
        .eq("status", "settlement")
        .order("created_at", { ascending: false })
        .limit(1)
        .single();

      setSubscription(data);
    } catch {
      /* silent - user is on free tier */
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchSubscription(); }, [fetchSubscription]);

  if (loading) {
    return <Skeleton className="h-48 rounded-[2rem]" />;
  }

  const planId = subscription?.plan_id || "free";
  const config = tierConfig[planId] || tierConfig.free;
  const Icon = config.icon;

  const expiresAt = subscription?.expires_at 
    ? new Date(subscription.expires_at).toLocaleDateString("id-ID", { day: "numeric", month: "long", year: "numeric" })
    : null;

  return (
    <Link
      href="/dashboard/profile"
      className="block group"
    >
      <div className={`relative bg-gradient-to-br ${config.gradient} rounded-[2rem] p-6 overflow-hidden transition-transform duration-200 hover:scale-[1.02] active:scale-[0.98]`}>
        {/* Background Decoration */}
        <div className="absolute top-0 right-0 p-6 opacity-10 group-hover:scale-110 transition-transform duration-300">
          <Icon className="w-24 h-24" />
        </div>

        {/* Content */}
        <div className="relative z-10 flex flex-col justify-between h-full min-h-[120px]">
          <div className="flex items-center justify-between">
            <span className={`text-[10px] font-black uppercase tracking-[0.15em] ${config.textColor} opacity-60`}>
              Paket Langganan
            </span>
            <span className={`text-[10px] font-black px-2.5 py-1 rounded-full ${config.labelBg} uppercase tracking-widest`} style={{ fontFeatureSettings: '"calt"' }}>
              {planId === "free" ? "FREE" : subscription?.interval === "yearly" ? "TAHUNAN" : "BULANAN"}
            </span>
          </div>

          <div className="mt-4 space-y-2">
            <div className="flex items-center gap-2">
              <Icon className={`w-5 h-5 ${config.textColor}`} />
              <h3 className={`text-xl font-black ${config.textColor}`} style={{ fontFeatureSettings: '"calt"' }}>
                {config.label}
              </h3>
            </div>
            <p className={`text-xs font-semibold ${config.textColor} opacity-60 max-w-[220px]`} style={{ fontFeatureSettings: '"calt"' }}>
              {config.description}
            </p>
          </div>

          <div className="flex items-center justify-between mt-4 pt-3 border-t border-current/10">
            <div>
              {planId === "free" ? (
                <span className={`text-[10px] font-black ${config.textColor} opacity-60`} style={{ fontFeatureSettings: '"calt"' }}>
                  Upgrade untuk fitur lengkap →
                </span>
              ) : expiresAt ? (
                <span className={`text-[10px] font-black ${config.textColor} opacity-60`} style={{ fontFeatureSettings: '"calt"' }}>
                  Berlaku hingga {expiresAt}
                </span>
              ) : (
                <span className={`text-[10px] font-black ${config.textColor} opacity-60`} style={{ fontFeatureSettings: '"calt"' }}>
                  Aktif
                </span>
              )}
            </div>
            <ChevronRight className={`w-4 h-4 ${config.textColor} opacity-40 group-hover:opacity-100 group-hover:translate-x-0.5 transition-all`} />
          </div>
        </div>
      </div>
    </Link>
  );
}

"use client";

import { useState } from "react";
import { Info, Wallet } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { 
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter 
} from "@/components/ui/dialog";
import { CurrencyInput } from "@/components/ui/currency-input";
import { Goal } from "./goal-card";

interface GoalDepositModalProps {
  open: boolean;
  onClose: () => void;
  onSuccess: () => void;
  goal: Goal | null;
}

export function GoalDepositModal({ open, onClose, onSuccess, goal }: GoalDepositModalProps) {
  const [amount, setAmount] = useState<number>(0);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!goal || !amount || amount <= 0) {
      setError("Masukkan jumlah nominal yang valid.");
      return;
    }

    setIsLoading(true);
    setError("");

    try {
      const newAmount = Number(goal.current_amount) + amount;
      const res = await fetch(`/api/goals/${goal.id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ current_amount: newAmount }),
      });

      if (!res.ok) throw new Error("Gagal menambah dana");

      setAmount(0);
      onSuccess();
      onClose();
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : "Terjadi kesalahan sistem.");
    } finally {
      setIsLoading(false);
    }
  };

  if (!goal) return null;

  return (
    <Dialog open={open} onOpenChange={(o) => !o && onClose()}>
      <DialogContent className="sm:max-w-md rounded-[2rem] sm:rounded-[2.5rem] border-border/40 p-6 sm:p-8 max-h-[90vh] overflow-y-auto custom-scrollbar">
        <DialogHeader>
          <div 
            className="w-12 h-12 rounded-2xl flex items-center justify-center mb-4"
            style={{ backgroundColor: `${goal.color}15`, color: goal.color }}
          >
            <Wallet className="w-6 h-6" />
          </div>
          <DialogTitle className="text-2xl font-black tracking-tight">
            Tambah Dana
          </DialogTitle>
          <DialogDescription className="text-muted-foreground font-medium">
            Masukkan jumlah uang yang ingin Anda simpan untuk target <strong>{goal.title}</strong>.
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-6 pt-4">
          <div className="space-y-2 text-center">
            <Label className="text-xs font-black uppercase tracking-widest ml-1">Nominal Simpanan</Label>
            <CurrencyInput
              value={amount}
              onChange={setAmount}
              autoFocus
              className="h-14 text-xl font-bold text-center"
            />
            <p className="text-[11px] text-muted-foreground text-center pt-1 font-medium">
              Saldo saat ini: <span className="font-bold text-foreground">Rp {goal.current_amount.toLocaleString("id-ID")}</span> / 
              Rp {goal.target_amount.toLocaleString("id-ID")}
            </p>
          </div>

          {error && (
            <div className="flex items-center gap-2 p-3 rounded-xl bg-expense/10 text-expense text-xs font-bold">
              <Info className="w-4 h-4" /> {error}
            </div>
          )}

          <DialogFooter className="pt-2 sm:pt-4 flex flex-col sm:flex-row gap-2 sm:gap-0">
            <Button 
              type="button" 
              variant="ghost" 
              onClick={onClose}
              className="rounded-2xl h-12 px-6 font-bold w-full sm:w-auto order-last sm:order-first"
            >
              Batal
            </Button>
            <Button 
              type="submit" 
              disabled={isLoading || !amount || amount <= 0}
              className="rounded-2xl h-12 px-8 font-black bg-primary text-primary-foreground hover:brightness-110 shadow-lg active:scale-95 transition-all w-full sm:w-auto"
            >
              {isLoading ? "Memproses..." : "Konfirmasi Simpanan"}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

