"use client";

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { 
  DownloadCloud, 
  UploadCloud, 
  HardDrive, 
  RefreshCw,
  Package,
  AlertTriangle,
  CheckCircle2,
  XCircle
} from "lucide-react";
import type { Transaction } from "@/components/finance/transaction-form";

interface DataManagementCardProps {
  transactions: Transaction[];
}

export function DataManagementCard({ transactions }: DataManagementCardProps) {
  const [backupLoading, setBackupLoading] = useState(false);
  const [importLoading, setImportLoading] = useState(false);
  const [importResult, setImportResult] = useState<string | null>(null);

  return (
    <div className="space-y-10">
      <section>
        <h2 className="text-3xl font-black tracking-tight mb-6 flex items-center gap-3">
          Backup & <span className="text-primary">Ekspor.</span>
        </h2>
        <div className="border border-border/40 dark:border-border/10 bg-white dark:bg-card shadow-sm rounded-[2.5rem] p-8 md:p-10">
          <div className="flex items-center gap-4 mb-8">
            <div className="w-12 h-12 rounded-2xl bg-primary/20 flex items-center justify-center">
              <HardDrive className="w-6 h-6 text-primary" />
            </div>
            <div>
              <h3 className="text-xl font-black">Data Portabilitas</h3>
              <p className="text-sm text-muted-foreground font-medium">Cadangkan data Anda secara lokal kapan saja.</p>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="rounded-[2rem] border border-border/30 dark:border-border/10 bg-muted/10 dark:bg-muted/5 p-6 flex flex-col justify-between">
              <div>
                <h4 className="text-base font-black mb-2 flex items-center gap-2">
                  <Package className="w-5 h-5 text-primary" /> Ekspor Backup
                </h4>
                <p className="text-xs text-muted-foreground font-medium mb-6">
                  Unduh semua data transaksi, kategori, dan dompet dalam satu file JSON.
                </p>
              </div>
              <Button
                className="wise-button-pill w-full h-12 gap-2 bg-foreground text-background hover:scale-[1.02] active:scale-[0.98] font-black"
                disabled={backupLoading}
                onClick={async () => {
                  setBackupLoading(true);
                  try {
                    const res = await fetch("/api/backup");
                    const data = await res.json();
                    const blob = new Blob([JSON.stringify(data, null, 2)], { type: "application/json" });
                    const url = URL.createObjectURL(blob);
                    const a = document.createElement("a");
                    a.href = url;
                    a.download = `ngaturin_backup_${new Date().toISOString().split("T")[0]}.json`;
                    document.body.appendChild(a);
                    a.click();
                    document.body.removeChild(a);
                    URL.revokeObjectURL(url);
                  } finally { setBackupLoading(false); }
                }}
              >
                {backupLoading ? <RefreshCw className="w-4 h-4 animate-spin" /> : <DownloadCloud className="w-4 h-4" />}
                {backupLoading ? "Menyiapkan..." : "Unduh JSON"}
              </Button>
            </div>

            <div className="rounded-[2rem] border border-border/30 dark:border-border/10 bg-muted/10 dark:bg-muted/5 p-6 flex flex-col justify-between">
              <div>
                <h4 className="font-black mb-2 flex items-center gap-2">
                  <RefreshCw className="w-5 h-5 text-primary" /> Impor Data
                </h4>
                <p className="text-xs text-muted-foreground font-medium mb-6">
                  Pulihkan seluruh transaksi dari file cadangan yang Anda miliki.
                </p>
                {importResult && (
                  <div className="p-3 bg-secondary/10 dark:bg-secondary/20 text-secondary-foreground rounded-xl text-[10px] font-black mb-4 border border-secondary/20">
                    {importResult}
                  </div>
                )}
              </div>
              <label className="w-full cursor-pointer">
                <div className={`wise-button-pill w-full h-12 bg-secondary text-secondary-foreground hover:scale-[1.02] active:scale-[0.98] flex items-center justify-center gap-2 text-sm font-black transition-all ${
                  importLoading ? "opacity-50 pointer-events-none" : ""
                }`}>
                  {importLoading ? <RefreshCw className="w-4 h-4 animate-spin" /> : <UploadCloud className="w-4 h-4" />}
                  {importLoading ? "Mengimpor..." : "Pilih File"}
                </div>
                <input
                  type="file"
                  accept=".json"
                  className="hidden"
                  disabled={importLoading}
                  onChange={async (e) => {
                    const file = e.target.files?.[0];
                    if (!file) return;
                    setImportLoading(true);
                    setImportResult(null);
                    try {
                      const text = await file.text();
                      const json = JSON.parse(text);
                      const res = await fetch("/api/backup", {
                        method: "POST",
                        headers: { "Content-Type": "application/json" },
                        body: JSON.stringify({ transactions: json.transactions || [] }),
                      });
                      const result = await res.json();
                      if (!res.ok) throw new Error(result.error);
                      setImportResult(`Berhasil mengimpor ${result.imported} transaksi!`);
                    } catch (err: any) {
                      setImportResult(`Gagal: ${err.message}`);
                    } finally {
                      setImportLoading(false);
                      e.target.value = "";
                    }
                  }}
                />
              </label>
            </div>
          </div>
        </div>
      </section>
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { cn } from "@/lib/utils";
import { createClient } from "@/lib/supabase/client";
import { User } from "@supabase/supabase-js";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Camera, Save, KeyRound, Loader2, Eye, EyeOff, CheckCircle2, Circle, AlertTriangle, Trash2, RefreshCw, ShieldCheck, CalendarDays, Wallet, Bot } from "lucide-react";
import {
  Select, SelectContent, SelectItem, SelectTrigger, SelectValue,
} from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { CategoryIcon } from "@/components/categories/category-icon";
import { useToast } from "@/lib/toast-context";
import { useUserPreferences, ACCENT_COLORS } from "@/components/providers/user-preferences-provider";
import { Subscription } from "./profile-subscription-tab";

interface ProfileFormProps {
  user: User;
  subscription: Subscription | null;
}

export function ProfileForm({ user, subscription }: ProfileFormProps) {
  const { showDecimals, accentColor, updatePreferences } = useUserPreferences();
  const [fullName, setFullName] = useState(user.user_metadata?.full_name || "");
  const [avatarUrl, setAvatarUrl] = useState(user.user_metadata?.avatar_url || "");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);
  const [isUpdatingProfile, setIsUpdatingProfile] = useState(false);
  const [isUpdatingPassword, setIsUpdatingPassword] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [isResetting, setIsResetting] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  const [resetConfirmText, setResetConfirmText] = useState("");
  const [deleteConfirmText, setDeleteConfirmText] = useState("");
  const [isResetDialogOpen, setIsResetDialogOpen] = useState(false);
  const [isDeleteDialogOpen, setIsDeleteDialogOpen] = useState(false);
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  // Auto-save settings state
  const [paydayDay, setPaydayDay] = useState<string>("");
  const [primaryWalletId, setPrimaryWalletId] = useState<string>("");
  const [walletsList, setWalletsList] = useState<{id: string, name: string, icon: string, color: string}[]>([]);
  const [isSavingAutoSave, setIsSavingAutoSave] = useState(false);
  const [isLoadingAutoSave, setIsLoadingAutoSave] = useState(true);
  
  const supabase = createClient();
  const { showToast } = useToast();
  const router = useRouter();

  // Fetch auto-save profile and wallets on mount
  useEffect(() => {
    const fetchAutoSaveData = async () => {
      try {
        const [profileRes, walletsRes] = await Promise.all([
          fetch("/api/user/profile"),
          fetch("/api/wallets?balance=false"),
        ]);
        const profileData = await profileRes.json();
        const walletsData = await walletsRes.json();
        
        if (profileData.payday_day) setPaydayDay(String(profileData.payday_day));
        if (profileData.primary_wallet_id) setPrimaryWalletId(profileData.primary_wallet_id);
        if (Array.isArray(walletsData)) setWalletsList(walletsData);
      } catch (err) {
        console.error("Failed to fetch auto-save data:", err);
      } finally {
        setIsLoadingAutoSave(false);
      }
    };
    fetchAutoSaveData();
  }, []);

  const handleSaveAutoSaveSettings = async () => {
    setIsSavingAutoSave(true);
    try {
      const res = await fetch("/api/user/profile", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          payday_day: paydayDay ? Number(paydayDay) : null,
          primary_wallet_id: primaryWalletId || null,
        }),
      });
      if (!res.ok) {
        const d = await res.json();
        throw new Error(d.error || "Gagal menyimpan");
      }
      showToast("success", "Pengaturan auto-save berhasil disimpan!");
    } catch (err: any) {
      showToast("error", err.message || "Gagal menyimpan pengaturan auto-save");
    } finally {
      setIsSavingAutoSave(false);
    }
  };

  const handleUpdateProfile = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsUpdatingProfile(true);
    setMessage(null);

    try {
      const { error } = await supabase.auth.updateUser({
        data: { full_name: fullName }
      });

      if (error) throw error;
      setMessage({ type: 'success', text: 'Profil berhasil diperbarui!' });
      showToast('success', 'Profil berhasil diperbarui!');
    } catch (err: any) {
      setMessage({ type: 'error', text: err.message || 'Gagal memperbarui profil' });
      showToast('error', err.message || 'Gagal memperbarui profil');
    } finally {
      setIsUpdatingProfile(false);
    }
  };

  const hasMinLength = password.length >= 8;
  const hasUppercase = /[A-Z]/.test(password);
  const hasLowercase = /[a-z]/.test(password);
  const hasNumber = /[0-9]/.test(password);
  const hasSpecial = /[!@#$%^&*(),.?":{}|<>]/.test(password);
  const isPasswordValid = hasMinLength && hasUppercase && hasLowercase && hasNumber && hasSpecial;

  const handleUpdatePassword = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!isPasswordValid) {
      setMessage({ type: 'error', text: 'Silakan penuhi semua kriteria password yang diminta.' });
      return;
    }

    if (password !== confirmPassword) {
      setMessage({ type: 'error', text: 'Konfirmasi password tidak cocok!' });
      return;
    }

    setIsUpdatingPassword(true);
    setMessage(null);

    try {
      const { error } = await supabase.auth.updateUser({ password });
      if (error) throw error;
      setMessage({ type: 'success', text: 'Kata sandi berhasil diperbarui!' });
      showToast('success', 'Kata sandi berhasil diperbarui!');
      setPassword("");
      setConfirmPassword("");
    } catch (err: any) {
      setMessage({ type: 'error', text: err.message || 'Gagal memperbarui kata sandi' });
      showToast('error', err.message || 'Gagal memperbarui kata sandi');
    } finally {
      setIsUpdatingPassword(false);
    }
  };

  const handleUploadAvatar = async (e: React.ChangeEvent<HTMLInputElement>) => {
    try {
      if (!e.target.files || e.target.files.length === 0) return;
      
      const file = e.target.files[0];
      const fileExt = file.name.split('.').pop();
      const filePath = `${user.id}-${Math.random()}.${fileExt}`;

      setIsUploading(true);
      setMessage(null);

     
      const { error: uploadError } = await supabase.storage
        .from('avatars')
        .upload(filePath, file);

      if (uploadError) throw uploadError;

      
      const { data } = supabase.storage.from('avatars').getPublicUrl(filePath);
      const publicUrl = data.publicUrl;

     
      const { error: updateError } = await supabase.auth.updateUser({
        data: { avatar_url: publicUrl }
      });

      if (updateError) throw updateError;

      setAvatarUrl(publicUrl);
      setMessage({ type: 'success', text: 'Foto profil berhasil diunggah!' });
      showToast('success', 'Foto profil berhasil diunggah!');
    } catch (err: any) {
      setMessage({ type: 'error', text: err.message || 'Gagal mengunggah foto profil.' });
      showToast('error', err.message || 'Gagal mengunggah foto profil.');
    } finally {
      setIsUploading(false);
    }
  };

  const handleResetAccount = async () => {
    if (resetConfirmText !== "RESET") return;
    setIsResetting(true);
    try {
      const res = await fetch("/api/user/reset", { method: "POST" });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Gagal mereset akun");
      showToast("success", "Akun berhasil direset! Semua data Anda telah dihapus.");
      setIsResetDialogOpen(false);
      setResetConfirmText("");
      setTimeout(() => window.location.reload(), 1500);
    } catch (err: any) {
      showToast("error", err.message);
    } finally {
      setIsResetting(false);
    }
  };

  const handleDeleteAccount = async () => {
    if (deleteConfirmText !== "HAPUS") return;
    setIsDeleting(true);
    try {
      const res = await fetch("/api/user/delete", { method: "POST" });
      const data = await res.json();
      if (!res.ok) throw new Error(data.error || "Gagal menghapus akun");
      setIsDeleteDialogOpen(false);
      router.push("/auth/account-deleted"); // Redirect ke halaman informasi hapus akun berhasil
    } catch (err: any) {
      showToast("error", err.message);
      setIsDeleting(false);
    }
  };

  return (
    <div className="space-y-10">
      {message && (
        <div className={`p-5 rounded-[1.5rem] border text-sm font-bold flex items-center gap-3 animate-in fade-in slide-in-from-top-2 ${
          message.type === 'success' ? 'bg-primary/10 border-primary/20 text-primary-foreground' : 'bg-red-500/10 border-red-500/20 text-red-600'
        }`}>
          {message.type === 'success' ? <CheckCircle2 className="w-5 h-5" /> : <AlertTriangle className="w-5 h-5" />}
          {message.text}
        </div>
      )}

      {/* Informasi Dasar Section */}
      <section>
        <h2 className="text-3xl font-black tracking-tight mb-6 flex items-center gap-3">
          Informasi <span className="text-primary">Dasar.</span>
        </h2>
        <Card className="border border-border/40 bg-white dark:bg-card shadow-sm rounded-[2.5rem] overflow-hidden">
          <CardContent className="p-8 md:p-10">
            <form onSubmit={handleUpdateProfile} className="space-y-8">
              <div className="flex flex-col sm:flex-row items-center gap-8">
                <div className="relative group">
                  <div className="w-32 h-32 rounded-full overflow-hidden bg-muted border-4 border-border/30 flex items-center justify-center transition-transform duration-300 group-hover:scale-105">
                    {avatarUrl ? (
                      <img src={avatarUrl} alt="Avatar" className="w-full h-full object-cover" />
                    ) : (
                      <span className="text-4xl font-black text-muted-foreground uppercase">
                        {fullName ? fullName.charAt(0) : user.email?.charAt(0)}
                      </span>
                    )}
                  </div>
                 
                  <label className="absolute inset-0 flex items-center justify-center bg-black/60 text-white opacity-0 group-hover:opacity-100 transition-opacity rounded-full cursor-pointer">
                    {isUploading ? <Loader2 className="w-8 h-8 animate-spin" /> : <Camera className="w-8 h-8" />}
                    <input type="file" accept="image/*" className="hidden" onChange={handleUploadAvatar} disabled={isUploading} />
                  </label>
                </div>
                <div className="flex-1 space-y-2 text-center sm:text-left">
                  <div className="flex flex-wrap items-center gap-3 justify-center sm:justify-start">
                    <h4 className="font-black text-xl">Foto Profil</h4>
                    {subscription ? (
                      <span className="inline-flex items-center gap-1 px-3 py-1 rounded-full bg-primary text-primary-foreground text-[10px] font-black uppercase tracking-wider shadow-sm">
                        <CheckCircle2 className="w-3 h-3" /> PRO Member
                      </span>
                    ) : (
                      <span className="inline-flex items-center gap-1 px-3 py-1 rounded-full bg-muted/20 text-muted-foreground text-[10px] font-black uppercase tracking-wider">
                        Free Account
                      </span>
                    )}
                  </div>
                  <p className="text-sm text-muted-foreground font-medium">Bantu kami mengenal Anda lebih baik.</p>
                  <Button type="button" variant="outline" size="sm" className="mt-2 rounded-full font-bold px-6 border-border/40 dark:border-border/10 hover:bg-muted/50 dark:hover:bg-muted/10 transition-all relative">
                    {isUploading ? 'Mengunggah...' : 'Unggah Foto Baru'}
                    <input type="file" accept="image/*" className="absolute inset-0 opacity-0 cursor-pointer" onChange={handleUploadAvatar} disabled={isUploading} />
                  </Button>
                </div>
              </div>

              <div className="grid gap-6">
                <div className="grid gap-2.5">
                  <Label htmlFor="email" className="font-bold text-sm ml-1">Alamat Email</Label>
                  <Input id="email" type="email" value={user.email} disabled className="h-14 rounded-2xl bg-muted/30 border-border/30 font-semibold px-5" />
                  <p className="text-[10px] text-muted-foreground ml-1">Email tidak dapat diubah untuk saat ini.</p>
                </div>
                <div className="grid gap-2.5">
                  <Label htmlFor="fullName" className="font-bold text-sm ml-1 text-foreground">Nama Lengkap</Label>
                  <Input 
                    id="fullName" 
                    value={fullName}
                    onChange={(e) => setFullName(e.target.value)}
                    placeholder="Masukkan nama lengkap Anda"
                    className="h-14 rounded-2xl border-border/40 dark:border-border/10 dark:bg-muted/5 focus:border-primary focus:ring-primary/20 font-semibold px-5"
                  />
                </div>
              </div>

              <Button type="submit" className="wise-button-pill w-full sm:w-auto bg-primary text-primary-foreground hover:scale-[1.02] active:scale-[0.98] h-14 px-10 text-base font-black shadow-lg shadow-primary/20" disabled={isUpdatingProfile}>
                {isUpdatingProfile ? <Loader2 className="w-5 h-5 mr-2 animate-spin" /> : <Save className="w-5 h-5 mr-2" />}
                {isUpdatingProfile ? 'Menyimpan...' : 'Simpan Perubahan'}
              </Button>
            </form>
          </CardContent>
        </Card>
      </section>

      {/* Preferensi Tampilan Section */}
      <section>
        <h2 className="text-3xl font-black tracking-tight mb-6 flex items-center gap-3">
          Preferensi <span className="text-primary">Tampilan.</span>
        </h2>
        <Card className="border border-border/40 bg-white dark:bg-card shadow-sm rounded-[2.5rem] overflow-hidden">
          <CardContent className="p-8 md:p-10 space-y-10">
            {/* Decimal Toggle */}
            <div className="flex items-center justify-between gap-4 p-6 rounded-[2rem] bg-muted/5 border border-border/10">
              <div className="space-y-1">
                <h4 className="font-black text-lg">Tampilkan Desimal</h4>
                <p className="text-sm text-muted-foreground font-medium">Tampilkan dua angka di belakang koma (Rp 0,00).</p>
              </div>
              <Switch 
                checked={showDecimals} 
                onCheckedChange={(checked) => updatePreferences({ showDecimals: checked })} 
              />
            </div>

            {/* Color Accent Picker */}
            <div className="space-y-6">
              <div className="space-y-1">
                <h4 className="font-black text-lg ml-1">Aksen Warna Premium</h4>
