"use client";

import React, { createContext, useContext, useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";

export const ACCENT_COLORS = [
  { id: "wise-green", name: "Wise Green", hsl: "97 74% 67%", hex: "#9fe870" },
  { id: "ocean-blue", name: "Ocean Blue", hsl: "197 100% 61%", hex: "#38c8ff" },
  { id: "royal-purple", name: "Royal Purple", hsl: "260 100% 77%", hex: "#b18cff" },
  { id: "sunset-orange", name: "Sunset Orange", hsl: "25 100% 61%", hex: "#ff8c38" },
  { id: "emerald-deep", name: "Emerald Deep", hsl: "145 63% 49%", hex: "#2ecc71" },
  { id: "soft-charcoal", name: "Soft Charcoal", hsl: "120 2% 27%", hex: "#454745" },
];

interface UserPreferencesContextType {
  showDecimals: boolean;
  accentColor: string;
  updatePreferences: (prefs: Partial<{ showDecimals: boolean; accentColor: string }>) => Promise<void>;
  isLoading: boolean;
}

const UserPreferencesContext = createContext<UserPreferencesContextType | undefined>(undefined);

export function UserPreferencesProvider({ children }: { children: React.ReactNode }) {
  const [showDecimals, setShowDecimals] = useState(false);
  const [accentColor, setAccentColor] = useState("wise-green");
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    async function loadPreferences() {
      try {
        const res = await fetch("/api/user/profile");
        const data = await res.json();
        if (data) {
          if (data.show_decimals !== undefined) setShowDecimals(data.show_decimals);
          if (data.accent_color) setAccentColor(data.accent_color);
        }
      } catch (error) {
        console.error("Failed to load user preferences:", error);
      } finally {
        setIsLoading(false);
      }
    }
    loadPreferences();
  }, []);

  // Effect to update CSS variables when accentColor changes
  useEffect(() => {
    const selected = ACCENT_COLORS.find((c) => c.id === accentColor) || ACCENT_COLORS[0];
    document.documentElement.style.setProperty("--primary", selected.hsl);

    // Also update primary-foreground for accessibility if needed
    // For now, most of our accents work well with dark green or black text
    if (accentColor === "soft-charcoal" || accentColor === "emerald-deep") {
      document.documentElement.style.setProperty("--primary-foreground", "0 0% 100%"); // White text
    } else {
      document.documentElement.style.setProperty("--primary-foreground", "94 100% 10%"); // Dark green text
    }
  }, [accentColor]);

  const updatePreferences = async (newPrefs: Partial<{ showDecimals: boolean; accentColor: string }>) => {
    // Optimistic UI
    if (newPrefs.showDecimals !== undefined) setShowDecimals(newPrefs.showDecimals);
    if (newPrefs.accentColor !== undefined) setAccentColor(newPrefs.accentColor);

    // Map to snake_case for API
    const apiPayload: any = {};
    if (newPrefs.showDecimals !== undefined) apiPayload.show_decimals = newPrefs.showDecimals;
    if (newPrefs.accentColor !== undefined) apiPayload.accent_color = newPrefs.accentColor;

    try {
      await fetch("/api/user/profile", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(apiPayload),
      });
    } catch (error) {
      console.error("Failed to update preferences:", error);
      // Revert if failed? Or just log.
    }
  };

  return (
    <UserPreferencesContext.Provider value={{ showDecimals, accentColor, updatePreferences, isLoading }}>
      {children}
    </UserPreferencesContext.Provider>
  );
}

export function useUserPreferences() {
  const context = useContext(UserPreferencesContext);
  if (context === undefined) {
    throw new Error("useUserPreferences must be used within a UserPreferencesProvider");
  }
  return context;
}

import { useState, useMemo, useEffect } from "react";
import type { Transaction } from "@/components/finance/transaction-form";

export interface InsightSummary {
  totalIncome: number;
  totalExpense: number;
  netCashflow: number;
  savingsRate: number;
  topCategory: string;
  topCategoryAmount: number;
  averageDailySpend: number;
}

export function useInsights(
  transactions: Transaction[], 
  selectedMonth: string, 
  selectedCategory: string = "all", 
  selectedWallet: string = "all",
  selectedType: string = "all"
) {
  
  // 1. Global Transactions (Ignore category & type filter for health metrics)
  const globalFilteredTxs = useMemo(() => {
    return transactions.filter((tx) => {
      const date = new Date(tx.date);
      const txMonth = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}`;
      const monthMatch = selectedMonth === "all" || txMonth === selectedMonth;
      const walletMatch = selectedWallet === "all" || (tx as any).wallet_id === selectedWallet;
      return monthMatch && walletMatch;
    });
  }, [transactions, selectedMonth, selectedWallet]);

  // 2. Deep Filtered Transactions (Include category & type filter)
  const filteredTxs = useMemo(() => {
    return globalFilteredTxs.filter((tx) => {
      const categoryMatch = selectedCategory === "all" || tx.category === selectedCategory;
      const typeMatch = selectedType === "all" || tx.type === selectedType;
      return categoryMatch && typeMatch;
    });
  }, [globalFilteredTxs, selectedCategory, selectedType]);

  const calculateSummary = (txs: Transaction[]): InsightSummary => {
    const income = txs
      .filter((t) => t.type === "income")
      .reduce((sum, t) => sum + Number(t.amount || 0), 0);
    
    const expense = txs
      .filter((t) => t.type === "expense")
      .reduce((sum, t) => sum + Number(t.amount || 0), 0);

    const net = income - expense;
    const savingsRate = income > 0 ? (net / income) * 100 : 0;

    const uniqueDays = new Set(txs.map(t => t.date)).size;
    const avgDaily = uniqueDays > 0 ? expense / uniqueDays : 0;

    const categoryTotals = txs
      .filter(t => t.type === "expense")
      .reduce((acc, t) => {
        acc[t.category] = (acc[t.category] || 0) + Number(t.amount || 0);
        return acc;
      }, {} as Record<string, number>);

    let topCat = "Belum ada";
    let topAmt = 0;
    Object.entries(categoryTotals).forEach(([cat, amt]) => {
      if (amt > topAmt) {
        topAmt = amt;
        topCat = cat;
      }
    });

    return {
      totalIncome: income,
      totalExpense: expense,
      netCashflow: net,
      savingsRate: Math.max(0, savingsRate),
      topCategory: topCat,
      topCategoryAmount: topAmt,
      averageDailySpend: avgDaily,
    };
  };

  const globalSummary = useMemo(() => calculateSummary(globalFilteredTxs), [globalFilteredTxs]);
  const summary = useMemo(() => calculateSummary(filteredTxs), [filteredTxs]);

  // 3. Holistic Data States (Real-time, independent of filters)
  const [investments, setInvestments] = useState<any[]>([]);
  const [debts, setDebts] = useState<any[]>([]);
  const [bills, setBills] = useState<any[]>([]);
  const [isHolisticLoading, setIsHolisticLoading] = useState(false);

  const fetchHolisticData = async () => {
    setIsHolisticLoading(true);
    try {
      const [invRes, debtRes, billRes] = await Promise.all([
        fetch("/api/investments"),
        fetch("/api/debts"),
        fetch("/api/recurring-bills")
      ]);
      if (invRes.ok) setInvestments(await invRes.json());
      if (debtRes.ok) setDebts(await debtRes.json());
      if (billRes.ok) setBills(await billRes.json());
    } catch (err) {
      console.error("Failed to fetch holistic data:", err);
    } finally {
      setIsHolisticLoading(false);
    }
  };

  useEffect(() => {
    fetchHolisticData();
  }, []); // Only fetch once on mount/transactions change

  // AI Narrative Fetching
  const [aiNarrative, setAiNarrative] = useState<string>("Menganalisis data...");
  const [isAiLoading, setIsAiLoading] = useState(false);

  const fetchAiInsight = async () => {
    if (transactions.length === 0) {
        setAiNarrative("Mulai catat transaksimu untuk mendapatkan analisis cerdas di sini.");
        return;
    }
    
    setIsAiLoading(true);
    try {
      const res = await fetch("/api/insights/ai", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ 
          transactions: filteredTxs, 
          summary, 
          globalSummary,
          investments,
          debts,
          bills
        }),
      });
      const data = await res.json();
      setAiNarrative(data.narrative);
    } catch (err) {
      setAiNarrative("Gagal memuat analisis cerdas.");
    } finally {
      setIsAiLoading(false);
    }
  };

  useEffect(() => {
    fetchAiInsight();
  }, [selectedMonth, transactions.length, selectedCategory, selectedWallet, selectedType, investments.length, debts.length, bills.length]);

  return {
    filteredTransactions: filteredTxs,
    summary,
    globalSummary,
    aiNarrative,
    isAiLoading,
    investments,
    debts,
    bills,
    isHolisticLoading,
    refreshHolistic: fetchHolisticData
  };
}

"use client";

import { useEffect, useState } from "react";
import { createClient } from "@/lib/supabase/client";

export type SubscriptionStatus = 'free' | 'plus' | 'pro';

export function useSubscription() {
  const [status, setStatus] = useState<SubscriptionStatus>('free');
  const [loading, setLoading] = useState(true);
  const supabase = createClient();

  useEffect(() => {
    async function getSubscription() {
      try {
        const { data: { user } } = await supabase.auth.getUser();
        if (!user) {
          setStatus('free');
          return;
        }

        const { data, error } = await supabase
          .from("subscriptions")
          .select("*")
          .eq("user_id", user.id)
          .eq("status", "settlement")
          .gt("current_period_end", new Date().toISOString())
          .order("created_at", { ascending: false })
          .limit(1)
          .maybeSingle();

        if (data) {
          setStatus(data.plan_id as SubscriptionStatus);
        } else {
          setStatus('free');
        }
      } catch (error) {
        console.error("Error fetching subscription:", error);
        setStatus('free');
      } finally {
        setLoading(false);
      }
    }

    getSubscription();
  }, [supabase]);

  return { status, loading, isPlus: status === 'plus' || status === 'pro', isPro: status === 'pro' };
}
